<script>
// import { buttonsg } from '../assets/buttons_g.js' // Import the data from the external file
// import { buttonsp } from '../assets/buttons_p.js'
import { receptyG, receptyP } from '../components/read.js'
import Papa from 'papaparse'
//import New1 from './New1.vue'
// console.log(buttonsg[0].id)
// console.log(window.$rendered)
export default {
  data () {
    return {
      // buttonsg,
      // buttonsp,
      buttonsgreen: [{
        id: 0,
        label: ''
      }],
      buttonspurple: [{
        id: 0,
        label: ''
      }],
      recept: [{
        line: '',
        image: ''
      }],
      image: '',
      line: '',
      id: 0,
      home: true,
      rec: false,
      green: true
    }
  },
  mounted () {
    Papa.parse('buttonsg.csv', {
      download: true,
      header: true,
      skipEmptyLines: true,
      complete: (results) => {
        this.buttonsgreen = results.data
      }
    })
    Papa.parse('buttonsp.csv', {
      download: true,
      header: true,
      skipEmptyLines: true,
      complete: (results) => {
        this.buttonspurple = results.data
      }
    })
  },
  methods: {
    click (id) {
      if (this.green) {
        receptyG.then(result => {
          this.recept = result
          // console.log(result)
          this.image = result[id].image
          this.id = id // id is used in html line {{ recept[id].line }}
        })
      } else {
        receptyP.then(result => {
          this.recept = result
          this.image = result[id].image
          this.id = id
        }
        )
      }
    }
  }
}
</script>
